SIGIL = "!"
UNSOLICITED_WINDOW = 600    # seconds
SALIENCE_THRESHOLD = 0.7

state = {
    "memory": load_memory(),
    "last_push_ts": 0,
}

function on_user_message(text):
    if text.startswith(SIGIL):
        verb, args = parse_sigil(text[1:])
        apply_to_memory(state.memory, verb, args)   # bypasses the model
        return ack(verb)
    return agent.reply(text, state)

function on_agent_tick():
    candidate = agent.scan_for_signal(state)        # insight, contradiction, goal-done
    if candidate is none:
        return
    if candidate.salience < SALIENCE_THRESHOLD:
        log("below threshold", candidate)
        return
    if now() - state.last_push_ts < UNSOLICITED_WINDOW:
        log("rate-limited", candidate)
        return
    push_to_user(candidate.message)
    state.last_push_ts = now()
# Invariant: at most one unsolicited message per window; sigils never call the model.

CITATION_RE = /\[\[cite:([a-z0-9_-]+)\]\]/

function stream_with_citations(question, sources):
    prompt = build_prompt(question, sources, marker="[[cite:<id>]]")
    citations_seen = {}

    for chunk in llm.stream(prompt):
        text = chunk.delta
        cursor = 0
        for match in CITATION_RE.find_all(text):
            if match.start > cursor:
                yield {"type": "text_delta", "text": text[cursor:match.start]}
            cid = match.group(1)
            src = sources.get(cid)
            if src and cid not in citations_seen:
                citations_seen[cid] = src
            yield {"type": "citation", "id": cid, "source": src}
            cursor = match.end
        if cursor < len(text):
            yield {"type": "text_delta", "text": text[cursor:]}

    yield {"type": "done", "citations": citations_seen}

from langchain.chat_models import init_chat_model

# Some providers (Anthropic, OpenAI with web search, Google) emit citation
# annotations on text content blocks. LangChain normalises them into the
# Citation TypedDict on TextContentBlock.annotations.
model = init_chat_model("anthropic:claude-sonnet-4-5")

for chunk in model.stream(
    "Summarise the 2024 AI Safety Summit declarations, with citations.",
):
    # chunk.content is a list of content blocks (text, citation, etc.).
    for block in chunk.content or []:
        if isinstance(block, dict) and block.get("type") == "text":
            yield_text(block.get("text", ""))
            for ann in block.get("annotations") or []:
                if ann.get("type") == "citation":
                    yield_citation({
                        "id": ann.get("id"),
                        "url": ann.get("url"),
                        "title": ann.get("title"),
                        "start": ann.get("start_index"),
                        "end": ann.get("end_index"),
                        "cited_text": ann.get("cited_text"),
                    })

