// fullStream interleaves text-delta and source events.
for await (const part of result.fullStream) {
  switch (part.type) {
    case "text-delta":
      ui.appendText(part.textDelta);
      break;
    case "source":
      if (part.sourceType === "url") {
        ui.appendCitation({
          id: part.id,
          url: part.url,
          title: part.title,
        });
      }
      break;
    case "finish":
      ui.done();
      break;
  }
}

PROXY_PATH = "~/.agent/proxy.json"

# Schema kept deliberately tiny so the human will actually update it.
# {
#   "energy":      0..10,
#   "fatigue":     0..10,
#   "environment": one word,
#   "emoji":       optional single grapheme,
#   "updated_at":  iso8601
# }

function set_proxy(energy, fatigue, environment, emoji=none):
    proxy = {
        "energy": energy,
        "fatigue": fatigue,
        "environment": environment,
        "emoji": emoji,
        "updated_at": now_iso(),
    }
    atomic_write(PROXY_PATH, proxy)

function build_prompt(user_text):
    proxy = read_or_default(PROXY_PATH)
    shape = derive_shape(proxy)              # pace, length, depth, opens-threads?
    return [
        system(BASE_SYSTEM_PROMPT + "\nProxy: " + serialise(proxy) +
               "\nResponse shape: " + shape),
        user(user_text),
    ]

function derive_shape(proxy):
    if proxy.energy <= 3 or proxy.fatigue >= 7:
        return "short; one anchor; do not open new threads"
    if proxy.environment == "winding-down":
        return "stay present; no homework"
    return "normal"

function run_agent(task, cancel_token):
    messages = [system_prompt, user(task)]
    partial  = ""

    for step in 1..MAX_STEPS:
        if cancel_token.is_set():
            return halt("cancelled", partial=partial, step=step)

        stream = llm.stream(messages=messages, tools=TOOLS,
                            cancel_token=cancel_token)
        for chunk in stream:
            if cancel_token.is_set():
                stream.close()                       # tear down provider stream
                return halt("cancelled", partial=partial, step=step)
            partial += chunk.text
            ui.emit("text_delta", chunk.text)

        reply = finalise(stream)
        messages.append(reply)
        if not reply.tool_calls:
            return ok(reply.content, step=step)

        for call in reply.tool_calls:
            result = dispatch(call, cancel_token=cancel_token)  # tools honour the token
            if cancel_token.is_set():
                return halt("cancelled", partial=partial, step=step)
            messages.append(tool_result(call.id, result))

    return halt("budget_exhausted", partial=partial, step=MAX_STEPS)

