import { streamText } from "ai";
import { openai } from "@ai-sdk/openai";

const controller = new AbortController();

let partial = "";
const result = streamText({
  model: openai("gpt-4o-mini"),
  prompt: "Write a long essay about the history of the spreadsheet.",
  abortSignal: controller.signal,
  onAbort: ({ steps }) => {
    // onAbort fires instead of onFinish; surface partial state to the UI.
    ui.surfacePartial({ text: partial, completedSteps: steps.length });
  },
});

// Wire the UI stop button.
stopButton.onclick = () => controller.abort();

for await (const part of result.fullStream) {
  switch (part.type) {
    case "text-delta":
      partial += part.textDelta;
      ui.appendText(part.textDelta);
      break;
    case "abort":
      ui.markCancelled();
      break;
    case "finish":
      ui.done();
      break;
  }
}

from livekit.agents import AgentSession, TurnHandlingOptions

session = AgentSession(
    # ... stt / llm / tts plugins ...
    turn_handling=TurnHandlingOptions(
        interruption={
            "enabled": True,
            "mode": "adaptive",
            "resume_false_interruption": True,
        },
    ),
)


@session.on("user_interruption_detected")
def _on_user_interruption(ev):
    # User started speaking while the agent was still talking.
    # The session will stop synthesis automatically; surface partial state.
    ui.mark_agent_interrupted(reason="user_barge_in")


@session.on("agent_false_interruption")
def _on_false_interruption(ev):
    # Detector fired but the user didn't actually take the turn.
    ui.note("resumed after false interruption")


async def stop_button_pressed():
    # Explicit UI-driven cancel: stop any current agent speech immediately.
    await session.interrupt()

# Event vocabulary the client routes on:
#   text_delta   { text }
#   tool_start   { id, name, args }
#   tool_end     { id, result }
#   card         { schema, data }
#   suggestions  { items }
#   done         {}
#   error        { message }

function handle_request(req, last_event_id=none):
    cursor = resume_cursor(last_event_id) or new_cursor(req)
    set_sse_headers()

    for step in agent.run(cursor=cursor):
        for chunk in step.stream():
            yield sse(id=next_id(), event="text_delta",
                      data={"text": chunk.text})
        for call in step.tool_calls:
            yield sse(id=next_id(), event="tool_start",
                      data={"id": call.id, "name": call.name, "args": call.args})
            result = dispatch(call)
            yield sse(id=next_id(), event="tool_end",
                      data={"id": call.id, "result": result})
        for card in step.cards:
            yield sse(id=next_id(), event="card",
                      data={"schema": card.schema, "data": card.data})

    yield sse(id=next_id(), event="done", data={})
