interface Voice:
    capabilities: set      # subset of {"tts", "stt", "sts"}
    voices:       list

    function speak(text)        -> AudioStream
    function listen(audio)      -> TranscriptStream
    function converse(audio)    -> AudioStream     # realtime speech-to-speech

# Shared event vocabulary every implementation emits:
#   turn_start | partial_transcript | final_transcript
#   voice_activity_start | voice_activity_stop
#   barge_in   | audio_chunk | turn_end

function run_voice_agent(voice: Voice, mic, speaker):
    if "sts" in voice.capabilities:
        out = voice.converse(mic.stream())
        for ev in out:
            route(ev, speaker)                    # one path, realtime
        return

    require({"tts", "stt"}.issubset(voice.capabilities), "need tts+stt")
    for ev in voice.listen(mic.stream()):
        if ev.type == "final_transcript":
            reply = agent.reply(ev.text)
            for chunk in voice.speak(reply):
                speaker.play(chunk)
        elif ev.type == "barge_in":
            speaker.cancel()                      # stop_cancel hook
# The loop branches on capability, never on provider name.
